const input = $('Input — First Contact Telegram').first().json;
const text = (input.original_text ?? '').toLowerCase().trim();

let role = 'analyst';
let tenant = 'default';

// Parse inline customisation from original message
const roleMatch = text.match(/role:([\w-]+)/);
const tenantMatch = text.match(/tenant:([\w-]+)/);
if (roleMatch) role = roleMatch[1];
if (tenantMatch) tenant = tenantMatch[1];

const VALID_ROLES = ['analyst', 'operator', 'read-only', 'admin'];
if (!VALID_ROLES.includes(role)) role = 'analyst';

return [{ json: {
  user_id: input.user_id,
  channel: 'telegram',
  display_name: input.display_name,
  chat_id: input.chat_id,
  role,
  tenant,
  policy_set: 'default',
  onboarded_at: new Date().toISOString()
} }];
